D.b0k=new B.n("Show year",null,null,null,null,null,null,null,null,null,null)
D.b0n=new B.n("A ColorPicker control lets users select a color using a color spectrum, sliders, and text input. It includes RGB (Red, Green, Blue) and HSV (Hue, Saturation, Value) color representations.\n\nThe ColorPicker includes two spectrum shapes (box and ring) and several optional components that can be shown or hidden.",null,null,null,null,null,null,null,null,null,null)
D.b0q=new B.n("A simple DatePicker with a header",null,null,null,null,null,null,null,null,null,null)
D.b0A=new B.n("A multi-line TextBox",null,null,null,null,null,null,null,null,null,null)
D.b0D=new B.n("A simple PasswordBox in peekAlways mode",null,null,null,null,null,null,null,null,null,null)
D.b0F=new B.n("The TextBox control lets a user type text into an app. It's typically used to capture a single line of text, but can be configured to capture multiple lines of text. The text displays on the screen in a simple, uniform, plaintext format.\n\nTextBox has a number of features that can simplify text entry. It comes with a familiar, built-in context menu with support for copying and pasting text. It also has spell checking capabilities built in and enabled by default.",null,null,null,null,null,null,null,null,null,null)
D.b0I=new B.n("A DatePicker with flex layout",null,null,null,null,null,null,null,null,null,null)
